  ('social-worker-moex-06344', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '將決策權由中央向地方下放，增加民眾參與感，讓服務更具品質與彈性的敘述，比較傾向下列何種觀點？', '["分散化", "專業化", "官僚化", "垂直化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06345', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關「新公共管理」特色的敘述，下列何者最正確？', '["強調專業的裁量權，看重專業人員的能力", "強調行政組織的效率、彈性及解除管制等理念", "強調福利主義指導下的標準作業流程與規定", "強調政策的輸入面，看重自上而下的執行過程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06346', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '近年來探討新貧（new poverty）與工作貧窮（working poor）頗為普及，這兩種型態的貧窮概念間有同有 異，下列敘述何者錯誤？', '["二者均強調致貧原因係屬個人工作道德不佳", "二者均從勞動及就業的角度來討論貧窮", "新貧強調因社會變遷而讓人失業致落入貧窮；工作貧窮強調即使有工作，仍不足以滿足一般家庭需求", "新貧仍偏向概念討論，工作貧窮則具有實證基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06347', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在脫貧方案中「財產累積」策略成為普及的做法，其原則的組合，下列何者正確？①志願原則  ②直接', '["目的彈性化", "快速累積帳戶金額  ⑤資訊提供與訓練", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
